const body = $input.first().json.body || {};
const category = String(body.category || '').trim();
const ideaCount = Number(body.ideaCount || 1);
if (!category) throw new Error('category est obligatoire');
if (!Number.isInteger(ideaCount) || ideaCount < 1 || ideaCount > 5) throw new Error('ideaCount doit etre entre 1 et 5');
return [{ json: { category, ideaCount, workflowRunId: Number(body.workflowRunId || 0), template_id: body.templateId || null, tiktok_account_open_id: body.tiktokAccountOpenId || null } }];

const items = $input.all();
const workflowRunId = Number($('Validate Input').first().json.workflowRunId || 0);
return [{ json: { workflowRunId, createdCount: items.length } }];

const http = require('http');
const https = require('https');
const { URL } = require('url');
const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Summarize').item.json.workflowRunId || 0);
if (!baseUrl) throw new Error('APP_VIDEO_OPS_BACKEND_BASE_URL manquante');
if (!callbackSecret) throw new Error('APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET manquante');
if (!workflowRunId) throw new Error('workflowRunId manquant');
const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: "Creation ideas terminee.",
  responsePayload: JSON.stringify({ createdCount: Number($json.createdCount || 0) }),
});
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
let response = null;
let lastError = null;
for (let attempt = 1; attempt <= 6; attempt += 1) {
  try {
    response = await new Promise((resolve, reject) => {
      const req = client.request({
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          'X-Video-Ops-Callback-Secret': callbackSecret,
        },
      }, (res) => {
        let data = '';
        res.on('data', (chunk) => { data += chunk; });
        res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });
    if (response.statusCode >= 200 && response.statusCode < 300) {
      break;
    }
    lastError = 'Callback backend refuse: ' + response.statusCode + ' ' + response.body;
    if (response.statusCode !== 404 || attempt === 6) {
      throw new Error(lastError);
    }
  } catch (error) {
    lastError = error.message || String(error);
    if (attempt === 6) {
      throw error;
    }
  }
  await sleep(500 * attempt);
}
if (!response || response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error(lastError || 'Callback backend refuse.');
}
return [{ json: { ...$json, callbackStatusCode: response.statusCode } }];
